1	import { describe, it, expect } from "vitest";
2	import { quote } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote — base price list and processing fee", () => {
6	    it("empty item list → premium 5 G (only the processing fee)", () => {
7	      expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
8	    });
9	    it.todo("single sword (newcomer, plain) → premium 115 G (100 base + 10 first-insurance + 5 fee)");
