11	    it.todo("single staff (newcomer, plain) → premium 93 G (80 base + 8 first-insurance + 5 fee)");
12	    it.todo("single potion (newcomer, plain) → premium 49 G (40 base + 4 first-insurance + 5 fee)");
13	  });
14	
15	  describe("quote — component building block", () => {
16	    it.todo("2 runes (no block) → premium 60 G (50 base + 5 first-insurance + 5 fee)");
17	    it.todo("3 runes (block applies) → premium 71 G (60 base + 6 first-insurance + 5 fee)");
18	    it.todo("4 runes (no block — block requires exactly 3) → premium 115 G (100 base + 10 first-insurance + 5 fee)");
19	    it.todo("7 runes (block requires exactly 3, so all 7 billed individually) → premium 198 G (175 base + 17.5 first-insurance + 5 fee = 197.5 rounded up to 198)");
20	    it.todo("2 runes + 1 moonstone (different types, no block) → premium 88 G (75 base + 7.5 first-insurance + 5 fee = 87.5 rounded up)");
21	    it.todo("3 runes + 3 moonstones (two separate blocks) → premium 137 G (120 base + 12 first-insurance + 5 fee)");
22	  });
23	
24	  describe("quote — modifier thresholds", () => {
25	    it.todo("loyalty threshold: customer with exactly 2 years, plain sword → premium 95 G (100 base − 20 loyalty + 10 first-insurance + 5 fee)");
26	    it.todo("loyalty just below: customer with 1 year, plain sword → premium 115 G (no loyalty discount)");
27	    it.todo("high-enchantment threshold: sword with exactly enchantment 5 → premium 145 G (100 base + 30 high-enchant + 10 first-insurance + 5 fee)");
28	    it.todo("high-enchantment just below: sword with enchantment 4 → premium 115 G (no high-enchant surcharge)");
29	    it.todo("cursed and high-enchantment (sword enchant 5, cursed) → premium 195 G (100 base + 50 curse + 30 high-enchant + 10 first-insurance + 5 fee)");
30	  });
31	
32	  describe("quote — modifier scope on multi-item policies", () => {
33	    it.todo("cursed sword + plain amulet (newcomer) → premium 231 G (policy base 160 + 50 curse on sword only + 10 first-ins sword + 6 first-ins amulet + 5 fee)");
34	  });
35	
36	  describe("quote — integration examples", () => {
37	    it.todo("newcomer with a cursed sword (steel, enchant 3), 0 years, first contract → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
38	    it.todo("long-standing customer's second contract: cursed sword (enchant 7), 3 years, second quote → premium 160 G (100 + 50 + 30 − 20 + 10 − 15 + 5)");
39	  });
40	
41	  describe("claim — standard reimbursement", () => {
42	    it.todo("regular sword (steel, enchant 3), damage 500 G → payout 400 G (full minus 100 deductible)");
43	    it.todo("rune (no enchant/material), damage 200 G → payout 100 G (full minus 100 deductible)");
44	  });
45	
46	  describe("claim — enchantment and dragon-material clauses", () => {
47	    it.todo("dragon sword enchant exactly 8, damage 1000 G → payout 400 G (50%% rule wins, then deductible: 500 − 100)");
48	    it.todo("dragon sword enchant 9, damage 1000 G → payout 400 G (both clauses; 50%% wins, then deductible)");
49	    it.todo("dragon sword enchant 5, damage 800 G → payout 700 G (only dragon clause: full reimbursement, then deductible)");
50	    it.todo("steel sword enchant 9, damage 1000 G → payout 400 G (only high-enchant clause: 50%% first, then deductible)");
51	  });
52	
53	  describe("claim — deductible per damage event", () => {
54	    it.todo("dragon attack damages sword (500 G) + amulet (300 G) → payout 600 G (deductible applies once per damaged item)");
55	    it.todo("two-sword policy, dragon attack with two sword damage entries (500 + 400) → payout 700 G (each entry deducted: 400 + 300)");
56	  });
57	
58	  describe("claim — insurance sum and cap", () => {
59	    it.todo("policy of sword + amulet → insurance sum 1600 G, cap 3200 G");
60	    it.todo("policy with cursed sword (premium 165 G after modifiers) → cap still 2000 G (based on unmodified insurance value)");
61	    it.todo("policy of sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only), cap 3500 G");
62	    it.todo("cap exhaustion: sword policy (cap 2000), claim 1500 → payout 1400, remainingCap 600; claim 1500 → payout 600, remainingCap 0");
