73	    it.todo("CLI: two quote steps for same customer → second quote applies follow-up contract discount (long-standing scenario E32 yields 160 G)");
74	  });
75	
76	  describe("CLI — error handling (exit non-zero, stderr)", () => {
77	    it.todo("CLI: quote includes unknown item type (e.g. broomstick) → exits non-zero, error on stderr, no `results` on stdout");
78	    it.todo("CLI: claim references an item not in the policy (e.g. amulet damaged when only a sword insured) → exits non-zero, error on stderr");
79	    it.todo("CLI: claim damage entry with negative amount → exits non-zero, error on stderr");
80	    it.todo("CLI: claim contains more damage entries of a type than the policy covers (two sword damages, one sword insured) → exits non-zero, error on stderr");
